31	library IEEE;
32	use			IEEE.STD_LOGIC_1164.all;
33	use			IEEE.NUMERIC_STD.all;
34	
35	library PoC;
36	use			PoC.utils.all;
37	use			PoC.vectors.all;
38	
39	entity cache_tagunit_seq is
40		generic (
41			REPLACEMENT_POLICY : string				:= "LRU";
42			CACHE_LINES				 : positive			:= 32;
43			ASSOCIATIVITY			 : positive			:= 32;
44			TAG_BITS					 : positive			:= 128;
45			CHUNK_BITS				 : positive			:= 8;
46			TAG_BYTE_ORDER		 : T_BYTE_ORDER := LITTLE_ENDIAN;
47			USE_INITIAL_TAGS	 : boolean			:= false;
48			INITIAL_TAGS			 : T_SLM				:= (0 downto 0 => (127 downto 0 => '0'))
49		);
50		port (
51			Clock : in std_logic;
52			Reset : in std_logic;
53	
54			Replace							: in	std_logic;
55			Replaced						: out std_logic;
56			Replace_NewTag_rst	: out std_logic;
57			Replace_NewTag_rev	: out std_logic;
58			Replace_NewTag_nxt	: out std_logic;
59			Replace_NewTag_Data : in	std_logic_vector(CHUNK_BITS - 1 downto 0);
60			Replace_NewIndex		: out std_logic_vector(log2ceilnz(CACHE_LINES) - 1 downto 0);
61	
62			Request						 : in	 std_logic;
63			Request_ReadWrite	 : in	 std_logic;
64			Request_Invalidate : in	 std_logic;
65			Request_Tag_rst		 : out std_logic;
66			Request_Tag_rev		 : out std_logic;
67			Request_Tag_nxt		 : out std_logic;
68			Request_Tag_Data	 : in	 std_logic_vector(CHUNK_BITS - 1 downto 0);
69			Request_Index			 : out std_logic_vector(log2ceilnz(CACHE_LINES) - 1 downto 0);
70			Request_TagHit		 : out std_logic;
71			Request_TagMiss		 : out std_logic
72		);
73	end entity;
74	
75	
76	architecture rtl of cache_tagunit_seq is
77		attribute KEEP : boolean;
78	
79		constant SETS : positive := CACHE_LINES / ASSOCIATIVITY;
80	
81	begin
82		-- ==========================================================================================================================================================
83		-- Full-Assoziative Cache
84		-- ==========================================================================================================================================================
85		genFA : if CACHE_LINES = ASSOCIATIVITY generate
86			constant FA_CACHE_LINES				: positive := ASSOCIATIVITY;
87			constant FA_TAG_BITS					: positive := TAG_BITS;
88			constant FA_CHUNKS						: positive := div_ceil(FA_TAG_BITS, CHUNK_BITS);
89			constant FA_CHUNK_INDEX_BITS	: positive := log2ceilnz(FA_CHUNKS);
90			constant FA_MEMORY_INDEX_BITS : positive := log2ceilnz(FA_CACHE_LINES);
91	
92			constant FA_INITIAL_TAGS_RESIZED : T_SLM := resize(INITIAL_TAGS, FA_CACHE_LINES);
93	
94			subtype T_CHUNK is std_logic_vector(CHUNK_BITS - 1 downto 0);
95			type T_TAG_LINE is array (natural range <>) of T_CHUNK;
96	
97			type T_REPLACE_STATE is (ST_IDLE, ST_REPLACE);
98			type T_REQUEST_STATE is (ST_IDLE, ST_COMPARE, ST_READ);
99	
100			function to_validvector(slm : T_SLM) return std_logic_vector is
101				variable result : std_logic_vector(CACHE_LINES - 1 downto 0);
102			begin
103				result := (others => '0');
104				if not USE_INITIAL_TAGS then return result; end if;
105	
106				for I in slm'range loop
107					result(I) := '1';
108				end loop;
109				return result;
110			end function;
111	
112			function to_tagmemory(slm : T_SLM; row : natural) return T_TAG_LINE is
113				constant tag_line : std_logic_vector(slm'high(2) downto slm'low(2)) := get_row(slm, row);
114				variable result		: T_TAG_LINE(FA_CHUNKS - 1 downto 0);
115			begin
116	--			report "tagline @row " & INTEGER'image(row) & " = " & to_string(tag_line, 'h') severity NOTE;
117				for I in result'range loop
118					result(I) := tag_line((I * CHUNK_BITS) + CHUNK_BITS - 1 downto (I * CHUNK_BITS));
119				end loop;
120				return result;
121			end function;
122	
123			signal Replace_State		 : T_Replace_STATE := ST_IDLE;
124			signal Replace_NextState : T_Replace_STATE;
125			signal Request_State		 : T_REQUEST_STATE := ST_IDLE;
126			signal Request_NextState : T_REQUEST_STATE;
127	
128			signal RequestComplete : std_logic;
129	
130			signal NewTagSeqCounter_rst : std_logic;
131	--		signal NewTagSeqCounter_en			: STD_LOGIC;
132			signal NewTagSeqCounter_us	: unsigned(FA_CHUNK_INDEX_BITS - 1 downto 0) := (others => '0');
133			signal TagSeqCounter_rst		: std_logic;
134	--		signal TagSeqCounter_en					: STD_LOGIC;
135			signal TagSeqCounter_us			: unsigned(FA_CHUNK_INDEX_BITS - 1 downto 0) := (others => '0');
136	
137			signal TagMemory_we : std_logic;
138	
139			signal PartialTagHits : std_logic_vector(FA_CACHE_LINES - 1 downto 0);
140			signal TagHits_en			: std_logic;
141			signal TagHits_nxt		: std_logic_vector(FA_CACHE_LINES - 1 downto 0);
142			signal TagHits_nor		: std_logic;
143			signal TagHits_r			: std_logic_vector(FA_CACHE_LINES - 1 downto 0) := (others => '1');
144	
145			signal MemoryIndex_us : unsigned(FA_MEMORY_INDEX_BITS - 1 downto 0);
146			signal MemoryIndex_i	: std_logic_vector(FA_MEMORY_INDEX_BITS - 1 downto 0);
147	
148			signal ValidMemory : std_logic_vector(FA_CACHE_LINES - 1 downto 0) := to_validvector(INITIAL_TAGS);
149			signal ValidHit		 : std_logic;
150	
151			signal Policy_ReplaceIndex	 : std_logic_vector(FA_MEMORY_INDEX_BITS - 1 downto 0);
152			signal Policy_ReplaceIndex_d : std_logic_vector(FA_MEMORY_INDEX_BITS - 1 downto 0) := (others => '0');
153			signal ReplaceIndex_us			 : unsigned(FA_MEMORY_INDEX_BITS - 1 downto 0);
154	
155			signal TagHit_i	 : std_logic;
156			signal TagMiss_i : std_logic;
157	
158			signal TagAccess : std_logic																					 := '0';
159			signal TagIndex	 : std_logic_vector(FA_MEMORY_INDEX_BITS - 1 downto 0) := (others => '0');
160	
161		begin
162			process(Clock)
163			begin
164				if rising_edge(Clock) then
165					if (Reset = '1') then
166						Replace_State <= ST_IDLE;
167						Request_State <= ST_IDLE;
168					else
169						Replace_State <= Replace_NextState;
170						Request_State <= Request_NextState;
171					end if;
172				end if;
173			end process;
174	
175			process(Replace_State, Replace, NewTagSeqCounter_us)
176			begin
177				Replace_NextState <= Replace_State;
178	
179				Replace_NewTag_rst <= '0';
180				Replace_NewTag_rev <= '0';
181				Replace_NewTag_nxt <= '0';
182				Replaced					 <= '0';
183	
184				NewTagSeqCounter_rst <= '0';
185	--			NewTagSeqCounter_en					<= '0';
186				TagMemory_we				 <= '0';
187	
188				case Replace_State is
189					when ST_IDLE =>
190						Replace_NewTag_rst	 <= '1';
191						NewTagSeqCounter_rst <= '1';
192	
193						if (Replace = '1') then
194							Replace_NewTag_rst <= '0';
195							Replace_NewTag_nxt <= '1';
196	
197							NewTagSeqCounter_rst <= '0';
198	--						NewTagSeqCounter_en		<= '1';
199							TagMemory_we				 <= '1';
200	
201							Replace_NextState <= ST_REPLACE;
202						end if;
203	
204					when ST_REPLACE =>
205						Replace_NewTag_nxt <= '1';
206	--					NewTagSeqCounter_en			<= '1';
207						TagMemory_we			 <= '1';
208	
209						if NewTagSeqCounter_us = ite((TAG_BYTE_ORDER = LITTLE_ENDIAN), (FA_CHUNKS - 1), 0) then
210							Replaced <= '1';
211	
212							Replace_NextState <= ST_IDLE;
213						end if;
214	
215				end case;
216			end process;
217	
218			process(Request_State, Request, TagSeqCounter_us, TagHits_nor)
219			begin
220				Request_NextState <= Request_State;
221	
222				TagSeqCounter_rst <= '0';
223	--			TagSeqCounter_en						<= '0';
224				TagHits_en				<= '0';
225	
226				Request_Tag_rst <= '0';
227				Request_Tag_rev <= ite((TAG_BYTE_ORDER = LITTLE_ENDIAN), '0', '1');
228				Request_Tag_nxt <= '0';
229				RequestComplete <= '0';
230	
231				case Request_State is
232					when ST_IDLE =>
233						Request_Tag_rst		<= '1';
234						TagSeqCounter_rst <= '1';
235	
236						if (Request = '1') then
237							if (TagHits_nor = '1') then
238								RequestComplete <= '1';
239							else
240								Request_Tag_rst <= '0';
241								Request_Tag_nxt <= '1';
242	
243								TagSeqCounter_rst <= '0';
244	--							TagSeqCounter_en		<= '1';
245								TagHits_en				<= '1';
246	
247								Request_NextState <= ST_COMPARE;
248							end if;
249						end if;
250	
251					when ST_COMPARE =>
252						Request_Tag_nxt <= '1';
253	--					TagSeqCounter_en				<= '1';
254						TagHits_en			<= '1';
255	
256						if (TagHits_nor = '1') then
257							Request_Tag_rst		<= '1';
258							TagSeqCounter_rst <= '1';
259							RequestComplete		<= '1';
260	
261							Request_NextState <= ST_IDLE;
262						else
263							if TagSeqCounter_us = ite((TAG_BYTE_ORDER = LITTLE_ENDIAN), (FA_CHUNKS - 1), 0) then
264								RequestComplete <= '1';
265	
266								Request_NextState <= ST_READ;
267							end if;
268						end if;
269	
270					when ST_READ =>
271						Request_Tag_rst		<= '1';
272						TagSeqCounter_rst <= '1';
273	
274						if (Request = '1') then
275							if (TagHits_nor = '1') then
276								RequestComplete		<= '1';
277								Request_NextState <= ST_IDLE;
278							else
279								Request_Tag_rst <= '0';
280								Request_Tag_nxt <= '1';
281	
282								TagSeqCounter_rst <= '0';
283	--							TagSeqCounter_en		<= '1';
284								TagHits_en				<= '1';
285	
286								Request_NextState <= ST_COMPARE;
287							end if;
288						end if;
289	
290				end case;
291			end process;
292	
293			-- Counters
294			process(Clock)
295			begin
296				if rising_edge(Clock) then
297					-- NewTagSeqCounter
298					if ((Reset or NewTagSeqCounter_rst) = '1') then
299						if TAG_BYTE_ORDER = LITTLE_ENDIAN then
300							NewTagSeqCounter_us <= to_unsigned(0, NewTagSeqCounter_us'length);
301						else
302							NewTagSeqCounter_us <= to_unsigned((FA_CHUNKS - 1), NewTagSeqCounter_us'length);
303						end if;
304					else
305						if TAG_BYTE_ORDER = LITTLE_ENDIAN then
306							NewTagSeqCounter_us <= NewTagSeqCounter_us + 1;
307						else
308							NewTagSeqCounter_us <= NewTagSeqCounter_us - 1;
309						end if;
310					end if;
311	
312					-- TagSeqCounter
313					if ((Reset or TagSeqCounter_rst) = '1') then
314						if TAG_BYTE_ORDER = LITTLE_ENDIAN then
315							TagSeqCounter_us <= to_unsigned(0, TagSeqCounter_us'length);
316						else
317							TagSeqCounter_us <= to_unsigned((FA_CHUNKS - 1), TagSeqCounter_us'length);
318						end if;
319					else
320						if TAG_BYTE_ORDER = LITTLE_ENDIAN then
321							TagSeqCounter_us <= TagSeqCounter_us + 1;
322						else
323							TagSeqCounter_us <= TagSeqCounter_us - 1;
324						end if;
325					end if;
326				end if;
327			end process;
328	
329			-- generate comparators
330			genVectors : for I in 0 to FA_CACHE_LINES - 1 generate
331				constant C_TAGMEMORY : T_TAG_LINE(FA_CHUNKS - 1 downto 0) := to_tagmemory(FA_INITIAL_TAGS_RESIZED, I);
332				signal TagMemory		 : T_TAG_LINE(FA_CHUNKS - 1 downto 0) := C_TAGMEMORY;
333			begin
334	--			genASS : for j in 0 to FA_CHUNKS - 1 generate
335	--				assert FALSE report "line=" & INTEGER'image(I) & "	chunk=" & INTEGER'image(J) & "	tag=" & to_string(C_TAGMEMORY(J), 'h') severity NOTE;
336	--			end generate;
337	
338				process(Clock)
339				begin
340					if rising_edge(Clock) then
341						if ((ReplaceIndex_us = I) and (TagMemory_we = '1')) then
342							TagMemory(to_integer(NewTagSeqCounter_us)) <= Replace_NewTag_Data;
343						end if;
344					end if;
345				end process;
346	
347				PartialTagHits(I) <= to_sl(TagMemory(to_integer(TagSeqCounter_us)) = Request_Tag_Data);
348			end generate;
349	
350			-- TagHit accumulator
351			TagHits_nxt <= TagHits_r and PartialTagHits;
352			TagHits_nor <= slv_nor(TagHits_nxt);
353	
354			process(Clock)
355			begin
356				if rising_edge(Clock) then
357					if ((TagHit_i or TagMiss_i) = '1') then
358						TagHits_r <= (others => '1');
359					elsif (TagHits_en = '1') then
360						TagHits_r <= TagHits_nxt;
361					end if;
362				end if;
363			end process;
364	
365			-- convert hit-vector to binary index (cache line address)
366			MemoryIndex_us <= onehot2bin(TagHits_nxt);
367			MemoryIndex_i	 <= std_logic_vector(MemoryIndex_us);
368	
369			-- latching the ReplaceIndex
370			process(Clock)
371			begin
372				if rising_edge(Clock) then
373					if (Replace = '1') then
374						Policy_ReplaceIndex_d <= Policy_ReplaceIndex;
375					end if;
376				end if;
377			end process;
378	
379			ReplaceIndex_us <= unsigned(ite((Replace = '1'), Policy_ReplaceIndex, Policy_ReplaceIndex_d));
380	
381			-- Memories
382			process(Clock)
383			begin
384				if rising_edge(Clock) then
385					if (Replace = '1') then
386						ValidMemory(to_integer(unsigned(Policy_ReplaceIndex))) <= '1';
387					end if;
388				end if;
389			end process;
390	
391			ValidHit <= ValidMemory(to_integer(MemoryIndex_us));
392	
393			-- hit/miss calculation
394			TagHit_i	<= slv_or(TagHits_nxt) and ValidHit and RequestComplete;
395			TagMiss_i <= not (slv_or(TagHits_nxt) and ValidHit) and RequestComplete;
396	
397			-- outputs
398			Request_Index		<= MemoryIndex_i;
399			Request_TagHit	<= TagHit_i;
400			Request_TagMiss <= TagMiss_i;
401	
402			Replace_NewIndex <= Policy_ReplaceIndex;
403	
404			TagAccess <= TagHit_i			 when rising_edge(Clock);
405			TagIndex	<= MemoryIndex_i when rising_edge(Clock);
406	
407			-- replacement policy
408			Policy : entity PoC.cache_replacement_policy
409				generic map (
410					REPLACEMENT_POLICY => REPLACEMENT_POLICY,
411					CACHE_WAYS				 => FA_CACHE_LINES
412				)
413				port map (
414					Clock => Clock,
415					Reset => Reset,
416	
417					Replace		 => Replace,
418					ReplaceWay => Policy_ReplaceIndex,
419	
420					TagAccess	 => TagAccess,
421					ReadWrite	 => Request_ReadWrite,
422					Invalidate => Request_Invalidate,
423					HitWay		 => TagIndex
424				);
425		end generate;
426		-- ==========================================================================================================================================================
427		-- Direct-Mapped Cache
428		-- ==========================================================================================================================================================
429		genDM : if ASSOCIATIVITY = 1 generate
430			constant FA_CACHE_LINES				: positive := CACHE_LINES;
431			constant FA_TAG_BITS					: positive := TAG_BITS;
432			constant FA_MEMORY_INDEX_BITS : positive := log2ceilnz(FA_CACHE_LINES);
433	
434			signal FA_Tag	 : std_logic_vector(FA_TAG_BITS - 1 downto 0);
435			signal TagHits : std_logic_vector(FA_CACHE_LINES - 1 downto 0);
436	
437			signal FA_MemoryIndex_i		: std_logic_vector(FA_MEMORY_INDEX_BITS - 1 downto 0);
438			signal FA_MemoryIndex_us	: unsigned(FA_MEMORY_INDEX_BITS - 1 downto 0);
439			signal FA_ReplaceIndex_us : unsigned(FA_MEMORY_INDEX_BITS - 1 downto 0);
440	
441			signal ValidHit	 : std_logic;
442			signal TagHit_i	 : std_logic;
443			signal TagMiss_i : std_logic;
444		begin
445	--		-- generate comparators
446	--		genVectors : for i in 0 to FA_CACHE_LINES - 1 generate
447	--			TagHits(I)			<= to_sl(TagMemory(I) = FA_Tag);
448	--		end generate;
449	--
450	--		-- convert hit-vector to binary index (cache line address)
451	--		FA_MemoryIndex_us		<= onehot2bin(TagHits);
452	--		FA_MemoryIndex_i		<= std_logic_vector(FA_MemoryIndex_us);
453	--
454	--		-- Memories
455	--		FA_ReplaceIndex_us	<= FA_MemoryIndex_us;
456	--
457	--		process(Clock)
458	--		begin
459	--			if rising_edge(Clock) then
460	--				if (Replace = '1') then
461	--					TagMemory(to_integer(FA_ReplaceIndex_us))		<= NewTag;
462	--					ValidMemory(to_integer(FA_ReplaceIndex_us)) <= '1';
463	--				end if;
464	--			end if;
465	--		end process;
466	--
