491	--					ReplaceIndex							=> Policy_ReplaceIndex(I),
492	--
493	--					TagAccess									=> TagAccess(I),
494	--					Request_ReadWrite									=> Request_ReadWrite(I),
495	--					Invalidate								=> Invalidate(I),
496	--					Index											=> Policy_Index(I)
497	--				);
498	--		end generate;
499		end generate;
500		-- ==========================================================================================================================================================
501		-- Set-Assoziative Cache
502		-- ==========================================================================================================================================================
503		genSA : if (ASSOCIATIVITY > 1) and (SETS > 1) generate
504			constant FA_CACHE_LINES				: positive := CACHE_LINES;
505			constant SETINDEX_BITS				: natural	 := log2ceil(SETS);
506			constant FA_TAG_BITS					: positive := TAG_BITS;
507			constant FA_MEMORY_INDEX_BITS : positive := log2ceilnz(FA_CACHE_LINES);
508	
509			signal FA_Tag	 : std_logic_vector(FA_TAG_BITS - 1 downto 0);
510			signal TagHits : std_logic_vector(FA_CACHE_LINES - 1 downto 0);
511	
512			signal FA_MemoryIndex_i		: std_logic_vector(FA_MEMORY_INDEX_BITS - 1 downto 0);
513			signal FA_MemoryIndex_us	: unsigned(FA_MEMORY_INDEX_BITS - 1 downto 0);
514			signal FA_ReplaceIndex_us : unsigned(FA_MEMORY_INDEX_BITS - 1 downto 0);
515	
516			signal ValidHit	 : std_logic;
517			signal TagHit_i	 : std_logic;
518			signal TagMiss_i : std_logic;
519		begin
520	--		-- generate comparators
521	--		genVectors : for i in 0 to FA_CACHE_LINES - 1 generate
522	--			TagHits(I)			<= to_sl(TagMemory(I) = FA_Tag);
523	--		end generate;
